// === Config you can tweak ===
const SENDER = "noreply@statuspage.io";   // filter sender (case-insensitive)
const SOURCE_LABEL = "Airtable Status";   // appears beside the subject
const DEFAULT_LINK = "";                  // optional "Open" button link

// === Helpers ===
const clean = (s) => String(s ?? "").replace(/\s+/g, " ").trim();
// Slack mrkdwn section text limit ~3000 chars
const cap   = (s, n = 3000) => (s.length > n ? s.slice(0, n - 1) + "…" : s);
// Escape only &, <, > for Slack mrkdwn (keep * _ ~ ` for formatting)
const esc   = (s) => clean(s).replace(/&/g, "&amp;").replace(/</g, "&lt;").replace(/>/g, "&gt;");

// Decode common HTML entities from email sources before escaping for Slack
const decodeEntities = (s) => String(s ?? "")
  .replace(/&#(\d+);/g, (_, n) => String.fromCharCode(+n))
  .replace(/&quot;/g, '"')
  .replace(/&apos;/g, "'")
  .replace(/&amp;/g, "&")
  .replace(/&lt;/g, "<")
  .replace(/&gt;/g, ">");

const section = (mrkdwn) =>
  ({ type: "section", text: { type: "mrkdwn", text: cap(mrkdwn, 3000) } });

const maybeSection = (label, value, { code = false } = {}) => {
  const v = clean(value);
  if (!v) return null;
  const body = code ? "```" + v + "```" : esc(v);
  return section(`*${esc(label)}:*\n${body}`);
};

const oneLineList = (label, listOrString) => {
  const val = Array.isArray(listOrString)
    ? listOrString.filter(Boolean).map(clean).join(", ")
    : clean(listOrString);
  if (!val) return null;
  return section(`*${esc(label)}:* ${esc(val)}`);
};

const divider = () => ({ type: "divider" });

function buildBlocks(item = {}) {
  const {
    subject = "",
    summary = "",
    decisions = "",
    actions = "",
    meta = {},          // { urgency, sentiment, confidence }
    link = "",
    source = "",
  } = item;

  const blocks = [];

  // ---- Header (subject bold + optional source label) ----
  const sourceLabel = clean(source || SOURCE_LABEL);
  const headerMrkdwn =
    `*${esc(cap(subject || "Status update", 150))}*` +
    (sourceLabel ? `  ·  _${esc(sourceLabel)}_` : "");
  blocks.push(section(headerMrkdwn));

  // ---- Body sections ----
  const summarySec = maybeSection("Summary", cap(summary, 1200));
  if (summarySec) blocks.push(summarySec);

  const decisionsBody = Array.isArray(decisions) ? decisions.join("\n") : decisions;
  const decisionsSec = maybeSection("Decisions", decisionsBody);
  if (decisionsSec) blocks.push(decisionsSec);

  const actionsSec = oneLineList("Actions", actions);
  if (actionsSec) blocks.push(actionsSec);

  // ---- Meta row (only if urgency not "low") ----
  const urgency = clean(meta.urgency);
  const sentiment = clean(meta.sentiment);
  const confidence = clean(meta.confidence);
  const showMeta = urgency && urgency.toLowerCase() !== "low";

  if (showMeta && (urgency || sentiment || confidence)) {
    blocks.push(divider());
    const pieces = [
      urgency ? `*Urgency:* ${esc(urgency)}` : "",
      sentiment ? `*Sentiment:* ${esc(sentiment)}` : "",
      confidence ? `*Confidence:* ${esc(confidence)}` : "",
    ].filter(Boolean);
    blocks.push(section(pieces.join("   ·   ")));
  }

  // ---- Action button ----
  const openLink = clean(link) || DEFAULT_LINK;
  if (openLink) {
    blocks.push({
      type: "actions",
      elements: [
        {
          type: "button",
          text: { type: "plain_text", text: "Open", emoji: true },
          url: openLink,
        },
      ],
    });
  }

  return blocks;
}

function fromGmailLike(m, senderFilter) {
  // Accept both Gmail-like and pre-shaped items
  const from = clean(m?.From || m?.from);
  const subject = clean(m?.Subject || m?.subject);
  const summary = clean(m?.snippet || m?.summary);
  const link = clean(m?.link || m?.permalink || "");
  const source = clean(m?.source || SOURCE_LABEL);
  const meta = m?.meta || {};           // { urgency, sentiment, confidence }
  const decisions = m?.decisions || "";
  const actions = m?.actions || "";

  // Filter by sender if Gmail-like structure is present
  if (senderFilter && (m?.From || m?.from)) {
    if (!from || from.toLowerCase() !== senderFilter.toLowerCase()) return null;
  }

  return { subject, summary, decisions, actions, link, source, meta };
}

// === Main (n8n Code node) ===
const inputItems = $input.all();
const out = [];

for (const it of inputItems) {
  const j = it.json;

  // If a node handed us an array in one item, explode it into multiple logical items
  const arr = Array.isArray(j) ? j : [j];

  for (const raw of arr) {
    const shaped0 = fromGmailLike(raw, SENDER);
    if (!shaped0) continue;

    // Decode HTML entities from email sources before building Slack content
    const shaped = {
      ...shaped0,
      subject: decodeEntities(shaped0.subject || "Status update"),
      summary: decodeEntities(shaped0.summary || ""),
      decisions: Array.isArray(shaped0.decisions)
        ? shaped0.decisions.map(decodeEntities)
        : decodeEntities(shaped0.decisions || ""),
      actions: Array.isArray(shaped0.actions)
        ? shaped0.actions.map(decodeEntities)
        : decodeEntities(shaped0.actions || ""),
    };

    const blocks = buildBlocks(shaped);

    // 1) short text (for Slack "Notification Text" when using Blocks)
    const text = clean(shaped.subject || shaped.summary || "Status update");

    // 2) full simple-text body (subject + Summary) for Text-only messages
    const text_full =
      `*${clean(shaped.subject || "Status update")}*` +
      (shaped.summary ? `\n\n*Summary:*\n${clean(shaped.summary)}` : "");

    // Output for Slack/HTTP nodes
    out.push({
      json: {
        text,        // short fallback (use with Blocks)
        text_full,   // complete simple text (use when Message Type = Text)
        blocks,      // Slack blocks array (use when Message Type = Blocks (JSON))
        // channel: "C0123456789", // optional if you drive chat.postMessage via HTTP
      },
    });
  }
}

return out;
